    legacy_part_id text,
    legacy_org_id text,
    legacy_product_id text,
    code varchar(50),
    description varchar(200),
    stock_quantity int,
    minimum_quantity int,
    sale_price numeric(15, 2),
    cost_price numeric(15, 2),
    category varchar(30),
