  INSERT INTO public.product_categories (
    id,
    organization_id,
    name,
    description,
    created_at,
    created_by,
    updated_at,
    updated_by,
    deleted_at,
    deleted_by
  )
  SELECT
    uuid_generate_v5(v_namespace, 'product_category:' || src.legacy_category_id || ':' || src.legacy_org_id),
    organizations.id,
    src.name,
    src.description,
    COALESCE(src.created_at, now()),
    src.created_by,
    COALESCE(src.updated_at, COALESCE(src.created_at, now())),
    src.created_by,
    NULL,
    NULL
  FROM tmp_product_category_source AS src
  JOIN public.organizations AS organizations
    ON organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
  WHERE src.legacy_org_id IS NOT NULL
    AND src.name IS NOT NULL
  ON CONFLICT (id) DO UPDATE
  SET
    organization_id = EXCLUDED.organization_id,
    name = EXCLUDED.name,
    description = EXCLUDED.description,
    updated_at = EXCLUDED.updated_at,
    updated_by = EXCLUDED.updated_by,
    deleted_at = NULL,
    deleted_by = NULL;

  INSERT INTO public.suppliers (
    id,
    organization_id,
    name,
    person_type,
    trade_name,
    tax_id,
    state_registration,
    phone,
    whatsapp,
    email,
    website,
    zip_code,
    street,
    address_number,
    address_complement,
    neighborhood,
    city,
    state,
    contact_name,
    contact_role,
    contact_phone,
    contact_email,
    category,
    payment_term_days,
    credit_limit,
    is_active,
    notes,
    created_at,
    created_by,
    updated_at,
    updated_by,
    deleted_at,
    deleted_by
  )
  SELECT
    uuid_generate_v5(v_namespace, 'supplier:' || src.legacy_supplier_id),
    organizations.id,
    src.name,
    src.person_type,
    src.trade_name,
    src.tax_id,
    src.state_registration,
    COALESCE(src.phone, '0000000000'),
    src.whatsapp,
    src.email,
    src.website,
    src.zip_code,
    src.street,
    src.address_number,
    src.address_complement,
    src.neighborhood,
    src.city,
    src.state,
    src.contact_name,
    src.contact_role,
    src.contact_phone,
    src.contact_email,
    src.category,
    src.payment_term_days,
    src.credit_limit,
    COALESCE(src.is_active, true),
    src.notes,
    COALESCE(src.created_at, now()),
    src.created_by,
    COALESCE(src.updated_at, COALESCE(src.created_at, now())),
    src.created_by,
    NULL,
    NULL
  FROM tmp_supplier_source AS src
  JOIN public.organizations AS organizations
    ON organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
  WHERE src.legacy_org_id IS NOT NULL
    AND src.name IS NOT NULL
  ON CONFLICT (id) DO UPDATE
  SET
    organization_id = EXCLUDED.organization_id,
    name = EXCLUDED.name,
    person_type = EXCLUDED.person_type,
    trade_name = EXCLUDED.trade_name,
    tax_id = EXCLUDED.tax_id,
    state_registration = EXCLUDED.state_registration,
    phone = EXCLUDED.phone,
    whatsapp = EXCLUDED.whatsapp,
    email = EXCLUDED.email,
    website = EXCLUDED.website,
    zip_code = EXCLUDED.zip_code,
    street = EXCLUDED.street,
    address_number = EXCLUDED.address_number,
    address_complement = EXCLUDED.address_complement,
    neighborhood = EXCLUDED.neighborhood,
    city = EXCLUDED.city,
    state = EXCLUDED.state,
    contact_name = EXCLUDED.contact_name,
    contact_role = EXCLUDED.contact_role,
    contact_phone = EXCLUDED.contact_phone,
    contact_email = EXCLUDED.contact_email,
    category = EXCLUDED.category,
    payment_term_days = EXCLUDED.payment_term_days,
    credit_limit = EXCLUDED.credit_limit,
    is_active = EXCLUDED.is_active,
    notes = EXCLUDED.notes,
    updated_at = EXCLUDED.updated_at,
    updated_by = EXCLUDED.updated_by,
    deleted_at = NULL,
    deleted_by = NULL;

  INSERT INTO public.clients (
    id,
    organization_id,
    name,
    person_type,
    tax_id,
    phone,
    email,
    zip_code,
    street,
    address_number,
    address_complement,
    neighborhood,
    city,
    state,
    employee_responsible_id,
    responsible_employees,
    notes,
    created_at,
    created_by,
    updated_at,
    updated_by,
    deleted_at,
    deleted_by
  )
  SELECT
    uuid_generate_v5(v_namespace, 'client:' || src.legacy_client_id),
    organizations.id,
    src.name,
    src.person_type,
    src.tax_id,
    COALESCE(src.phone, '0000000000'),
    src.email,
    src.zip_code,
    src.street,
    src.address_number,
    src.address_complement,
    src.neighborhood,
    src.city,
    src.state,
    responsible_employee.id,
    (
      SELECT COALESCE(
        jsonb_agg(jsonb_build_object('employee_id', employees.id::text) ORDER BY items.ordinality),
        '[]'::jsonb
      )
      FROM jsonb_array_elements_text(COALESCE(src.legacy_responsible_employee_ids, '[]'::jsonb)) WITH ORDINALITY AS items(legacy_employee_id, ordinality)
      JOIN public.employees AS employees
        ON employees.id = uuid_generate_v5(v_namespace, 'employee:' || items.legacy_employee_id)
    ),
    src.notes,
    COALESCE(src.created_at, now()),
    src.created_by,
    COALESCE(src.updated_at, COALESCE(src.created_at, now())),
    src.created_by,
    NULL,
    NULL
  FROM tmp_client_source AS src
  JOIN public.organizations AS organizations
    ON organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
  LEFT JOIN public.employees AS responsible_employee
    ON src.legacy_employee_responsible_id IS NOT NULL
   AND responsible_employee.id = uuid_generate_v5(v_namespace, 'employee:' || src.legacy_employee_responsible_id)
  WHERE src.legacy_org_id IS NOT NULL
    AND src.name IS NOT NULL
  ON CONFLICT (id) DO UPDATE
  SET
    organization_id = EXCLUDED.organization_id,
    name = EXCLUDED.name,
    person_type = EXCLUDED.person_type,
    tax_id = EXCLUDED.tax_id,
    phone = EXCLUDED.phone,
    email = EXCLUDED.email,
    zip_code = EXCLUDED.zip_code,
    street = EXCLUDED.street,
    address_number = EXCLUDED.address_number,
    address_complement = EXCLUDED.address_complement,
    neighborhood = EXCLUDED.neighborhood,
    city = EXCLUDED.city,
    state = EXCLUDED.state,
    employee_responsible_id = EXCLUDED.employee_responsible_id,
    responsible_employees = EXCLUDED.responsible_employees,
    notes = EXCLUDED.notes,
    updated_at = EXCLUDED.updated_at,
    updated_by = EXCLUDED.updated_by,
    deleted_at = NULL,
    deleted_by = NULL;

  WITH product_rows AS (
    SELECT
      uuid_generate_v5(v_namespace, 'product:' || src.legacy_product_id) AS id,
      organizations.id AS organization_id,
      src.name,
      src.code::integer AS code,
      src.type,
      categories.id AS category_id,
      COALESCE(src.track_inventory, false) AS track_inventory,
      COALESCE(src.initial_stock_quantity, 0) AS initial_stock_quantity,
      src.unit_sale_price,
      src.unit_cost_price,
      src.notes,
      CASE
        WHEN src.type = 'group' THEN COALESCE(src.group_items, '[]'::jsonb)
        ELSE NULL
      END AS group_items,
      COALESCE(src.created_at, now()) AS created_at,
      src.created_by,
      COALESCE(src.updated_at, COALESCE(src.created_at, now())) AS updated_at,
      row_number() OVER (
        PARTITION BY organizations.id, src.code::integer
        ORDER BY
          COALESCE(src.updated_at, src.created_at, '-infinity'::timestamptz) DESC,
          src.legacy_product_id DESC
      ) AS rn
    FROM tmp_product_source AS src
    JOIN public.organizations AS organizations
      ON organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
    LEFT JOIN public.product_categories AS categories
      ON src.legacy_category_id IS NOT NULL
     AND categories.id = uuid_generate_v5(v_namespace, 'product_category:' || src.legacy_category_id || ':' || src.legacy_org_id)
    WHERE src.legacy_org_id IS NOT NULL
      AND src.name IS NOT NULL
      AND src.code IS NOT NULL
      AND btrim(src.code) ~ '^\d+$'
  )
  INSERT INTO public.products (
    id,
    organization_id,
    name,
    code,
    type,
    category_id,
    track_inventory,
    initial_stock_quantity,
    unit_sale_price,
    unit_cost_price,
    notes,
    group_items,
    created_at,
    created_by,
    updated_at,
    updated_by,
    deleted_at,
    deleted_by
  )
  SELECT
    id,
    organization_id,
    name,
    code,
    type,
    category_id,
    track_inventory,
    initial_stock_quantity,
    unit_sale_price,
    unit_cost_price,
    notes,
    group_items,
    created_at,
    created_by,
    updated_at,
    created_by,
    NULL,
    NULL
  FROM product_rows
  WHERE rn = 1
  ON CONFLICT (organization_id, code) WHERE deleted_at IS NULL DO UPDATE
  SET
    name = EXCLUDED.name,
    type = EXCLUDED.type,
    category_id = EXCLUDED.category_id,
    track_inventory = EXCLUDED.track_inventory,
    initial_stock_quantity = EXCLUDED.initial_stock_quantity,
    unit_sale_price = EXCLUDED.unit_sale_price,
    unit_cost_price = EXCLUDED.unit_cost_price,
    notes = EXCLUDED.notes,
    group_items = EXCLUDED.group_items,
    updated_at = EXCLUDED.updated_at,
    updated_by = EXCLUDED.updated_by,
    deleted_at = NULL,
    deleted_by = NULL;

  WITH part_rows AS (
    SELECT
      uuid_generate_v5(v_namespace, 'part:' || src.legacy_part_id) AS id,
      organizations.id AS organization_id,
      products.id AS product_id,
      src.code,
      src.description,
      COALESCE(src.stock_quantity, 0) AS stock_quantity,
      COALESCE(src.minimum_quantity, 0) AS minimum_quantity,
      COALESCE(src.sale_price, 0) AS sale_price,
      src.cost_price,
      src.category,
      src.brand,
      src.supplier_name,
      src.location,
      src.notes,
      COALESCE(src.created_at, now()) AS created_at,
      src.created_by,
      COALESCE(src.updated_at, COALESCE(src.created_at, now())) AS updated_at
    FROM tmp_part_source AS src
    JOIN public.organizations AS organizations
      ON organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
    LEFT JOIN tmp_product_source AS product_src
      ON product_src.legacy_product_id = src.legacy_product_id
    LEFT JOIN public.products AS products
      ON products.organization_id = organizations.id
     AND products.code = CASE
       WHEN btrim(product_src.code) ~ '^\d+$' THEN product_src.code::integer
       ELSE NULL
     END
     AND products.deleted_at IS NULL
    WHERE src.legacy_org_id IS NOT NULL
      AND src.description IS NOT NULL
      AND src.code IS NOT NULL
  )
  INSERT INTO public.parts (
    id,
    organization_id,
    product_id,
    code,
    description,
    stock_quantity,
    minimum_quantity,
    sale_price,
    cost_price,
    category,
    brand,
    supplier_name,
    location,
    notes,
    created_at,
    created_by,
    updated_at,
    updated_by,
    deleted_at,
    deleted_by
  )
  SELECT
    id,
    organization_id,
    product_id,
    code,
    description,
    stock_quantity,
    minimum_quantity,
    sale_price,
    cost_price,
    category,
    brand,
    supplier_name,
    location,
    notes,
    created_at,
    created_by,
    updated_at,
    created_by,
    NULL,
    NULL
  FROM part_rows
  ON CONFLICT (organization_id, code) DO UPDATE
  SET
    product_id = EXCLUDED.product_id,
    description = EXCLUDED.description,
    stock_quantity = EXCLUDED.stock_quantity,
    minimum_quantity = EXCLUDED.minimum_quantity,
    sale_price = EXCLUDED.sale_price,
    cost_price = EXCLUDED.cost_price,
    category = EXCLUDED.category,
    brand = EXCLUDED.brand,
    supplier_name = EXCLUDED.supplier_name,
    location = EXCLUDED.location,
    notes = EXCLUDED.notes,
    updated_at = EXCLUDED.updated_at,
    updated_by = EXCLUDED.updated_by,
    deleted_at = NULL,
    deleted_by = NULL;

  INSERT INTO public.vehicles (
    id,
    organization_id,
    client_id,
    license_plate,
    brand,
    model,
    year,
    color,
    engine,
    fuel_type,
    mileage,
    notes,
    created_at,
    created_by,
    updated_at,
    updated_by,
    deleted_at,
    deleted_by
  )
  SELECT
    uuid_generate_v5(v_namespace, 'vehicle:' || src.legacy_vehicle_id),
    organizations.id,
    clients.id,
    src.license_plate,
    src.brand,
    src.model,
    src.year,
    src.color,
    src.engine,
    src.fuel_type,
    src.mileage,
    src.notes,
    COALESCE(src.created_at, now()),
    src.created_by,
    COALESCE(src.updated_at, COALESCE(src.created_at, now())),
    src.created_by,
    NULL,
    NULL
  FROM tmp_vehicle_source AS src
  JOIN public.organizations AS organizations
    ON organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
  LEFT JOIN public.clients AS clients
    ON src.legacy_client_id IS NOT NULL
   AND clients.id = uuid_generate_v5(v_namespace, 'client:' || src.legacy_client_id)
  WHERE src.legacy_org_id IS NOT NULL
  ON CONFLICT (id) DO UPDATE
  SET
    organization_id = EXCLUDED.organization_id,
    client_id = EXCLUDED.client_id,
    license_plate = EXCLUDED.license_plate,
    brand = EXCLUDED.brand,
    model = EXCLUDED.model,
    year = EXCLUDED.year,
    color = EXCLUDED.color,
    engine = EXCLUDED.engine,
    fuel_type = EXCLUDED.fuel_type,
    mileage = EXCLUDED.mileage,
    notes = EXCLUDED.notes,
    updated_at = EXCLUDED.updated_at,
    updated_by = EXCLUDED.updated_by,
    deleted_at = NULL,
    deleted_by = NULL;

  RAISE NOTICE 'Skipped % suppliers without resolvable organization or name.', (
    SELECT count(*)
    FROM tmp_supplier_source AS src
    LEFT JOIN public.organizations AS organizations
      ON src.legacy_org_id IS NOT NULL
     AND organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
    WHERE src.legacy_org_id IS NULL
       OR src.name IS NULL
       OR organizations.id IS NULL
  );

  RAISE NOTICE 'Skipped % clients without resolvable organization or name.', (
    SELECT count(*)
    FROM tmp_client_source AS src
    LEFT JOIN public.organizations AS organizations
      ON src.legacy_org_id IS NOT NULL
     AND organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
    WHERE src.legacy_org_id IS NULL
       OR src.name IS NULL
       OR organizations.id IS NULL
  );

  RAISE NOTICE 'Skipped % product categories without resolvable organization or name.', (
    SELECT count(*)
    FROM tmp_product_category_source AS src
    LEFT JOIN public.organizations AS organizations
      ON src.legacy_org_id IS NOT NULL
     AND organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
    WHERE src.legacy_org_id IS NULL
       OR src.name IS NULL
       OR organizations.id IS NULL
  );

  RAISE NOTICE 'Skipped % products without resolvable organization, name, or code.', (
    SELECT count(*)
    FROM tmp_product_source AS src
    LEFT JOIN public.organizations AS organizations
      ON src.legacy_org_id IS NOT NULL
     AND organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
    WHERE src.legacy_org_id IS NULL
       OR src.name IS NULL
       OR src.code IS NULL
       OR organizations.id IS NULL
  );

  RAISE NOTICE 'Skipped % parts without resolvable organization, description, or code.', (
    SELECT count(*)
    FROM tmp_part_source AS src
    LEFT JOIN public.organizations AS organizations
      ON src.legacy_org_id IS NOT NULL
     AND organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
    WHERE src.legacy_org_id IS NULL
       OR src.description IS NULL
       OR src.code IS NULL
       OR organizations.id IS NULL
  );

  RAISE NOTICE 'Skipped % vehicles without resolvable organization.', (
    SELECT count(*)
    FROM tmp_vehicle_source AS src
    LEFT JOIN public.organizations AS organizations
      ON src.legacy_org_id IS NOT NULL
     AND organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
    WHERE src.legacy_org_id IS NULL
       OR organizations.id IS NULL
  );

  RAISE NOTICE 'Imported % vehicles without client reference.', (
    SELECT count(*)
    FROM tmp_vehicle_source AS src
    JOIN public.organizations AS organizations
      ON organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
    LEFT JOIN public.clients AS clients
      ON src.legacy_client_id IS NOT NULL
     AND clients.id = uuid_generate_v5(v_namespace, 'client:' || src.legacy_client_id)
    WHERE clients.id IS NULL
  );

  RAISE NOTICE 'Operational migration seed applied: suppliers, clients, vehicles, product categories, products, and parts.';
END;
$$;
